import React, { useEffect, useState } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authorizationEndpoint = 'https://authorization-server.com/auth';
const tokenEndpoint = 'https://authorization-server.com/token';
const scope = 'YOUR_SCOPES';
const codeChallengeMethod = 'S256';

const generateCodeVerifier = () => {
    const array = new Uint32Array(28);
    window.crypto.getRandomValues(array);
    return Array.from(array, dec => ('0' + dec.toString(16)).slice(-2)).join('');
};

const base64UrlEncode = (str) => {
    return btoa(str).replace(/=+$/, '').replace(/\+/g, '-').replace(/\//g, '_');
};

const sha256 = async (buffer) => {
    const hash = await crypto.subtle.digest('SHA-256', buffer);
    return new Uint8Array(hash);
};

const generateCodeChallenge = async (codeVerifier) => {
    const hashed = await sha256(new TextEncoder().encode(codeVerifier));
    return base64UrlEncode(hashed);
};

const App = () => {
    const [codeVerifier, setCodeVerifier] = useState('');
    const [codeChallenge, setCodeChallenge] = useState('');
    const [accessToken, setAccessToken] = useState(localStorage.getItem('access_token'));

    useEffect(() => {
        const initOAuth = async () => {
            const verifier = generateCodeVerifier();
            setCodeVerifier(verifier);
            const challenge = await generateCodeChallenge(verifier);
            setCodeChallenge(challenge);
        };
        initOAuth();
    }, []);

    const handleLogin = () => {
        const authUrl = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=${scope}&code_challenge=${codeChallenge}&code_challenge_method=${codeChallengeMethod}`;
        window.location.href = authUrl;
    };

    const handleRedirect = async () => {
        const params = new URLSearchParams(window.location.search);
        const code = params.get('code');

        if (code) {
            const response = await fetch(tokenEndpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded',
                },
                body: new URLSearchParams({
                    grant_type: 'authorization_code',
                    code: code,
                    redirect_uri: redirectUri,
                    client_id: clientId,
                    code_verifier: codeVerifier,
                }),
            });

            const data = await response.json();
            if (data.access_token) {
                localStorage.setItem('access_token', data.access_token);
                setAccessToken(data.access_token);
            }
        }
    };

    useEffect(() => {
        handleRedirect();
    }, []);

    return (
        <div>
            <h1>OAuth 2.0 SPA</h1>
            {accessToken ? (
                <div>
                    <h2>Welcome!</h2>
                    <p>Your access token: {accessToken}</p>
                </div>
            ) : (
                <button onClick={handleLogin}>Login with OAuth</button>
            )}
        </div>
    );
};

